#include<bits/stdc++.h>
using namespace std;
int m[101][101];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        for(int j=i+1;j<=n;j++)
        {
            scanf("%d",&m[i][j]);
        }
    }
    long long ans=m[1][2];
    for(int i=3;i<=n;i++)
    {
        int min1=1e9;
        for(int j=2;j<i;j++)
        {
            min1=min(min1,(m[1][i]+m[j][i]-m[1][j])/2);
        }
        ans+=min1;
    }
    printf("%lld",ans);
    return 0;
}
